class IsPhoneNumber(DirtyEquals[str]):
    """
    A class that checks if a value is a valid phone number, optionally restricted to a specific country.
    """

    # (national_regex, international_regex)
    _country_patterns = {
        'US': (
            re.compile(r'\d{10}'),
            re.compile(r'\+1\d{10}'),
        ),
        'GB': (
            re.compile(r'0\d{9,10}'),
            re.compile(r'\+44\d{9,10}'),
        ),
    }
    _generic_national_re = re.compile(r'\d{7,15}')
    _generic_international_re = re.compile(r'\+\d{8,17}')

    def __init__(self, country_code: Optional[str] = None):
        """
        Args:
            country_code: if provided, restrict validation to the national or international phone number
                format used by that country. If omitted, any generally-valid national or international
                phone number is accepted.

        ```py title="IsPhoneNumber"
        from dirty_equals import IsPhoneNumber

        assert '+1-555-123-4567' == IsPhoneNumber
        assert '555-123-4567' == IsPhoneNumber
        assert '555-123-4567' == IsPhoneNumber('US')
        assert '+1-555-123-4567' == IsPhoneNumber('US')
        assert '020 7946 0958' == IsPhoneNumber('GB')
        assert '555-123-4567' != IsPhoneNumber('GB')
        assert 1234567890 != IsPhoneNumber
        ```
        """
        self.country_code = country_code
        super().__init__(country_code or plain_repr('*'))

    def equals(self, other: Any) -> bool:
        if not isinstance(other, str):
            return False

        cleaned = re.sub(r'[\s\-.()]', '', other)
        if not cleaned:
            return False

        if self.country_code is None:
            return bool(
                self._generic_national_re.fullmatch(cleaned) or self._generic_international_re.fullmatch(cleaned)
            )

        patterns = self._country_patterns.get(self.country_code.upper())
        if patterns is None:
            # unknown country, fall back to generic international validation
            return bool(self._generic_international_re.fullmatch(cleaned))

        national_re, international_re = patterns
        return bool(national_re.fullmatch(cleaned) or international_re.fullmatch(cleaned))"}

